import json
import re

# Load the event and schema
with open('event.json') as f:
    event = json.load(f)
with open('schema.json') as f:
    schema = json.load(f)

# Manual validation against the schema
errors = []

# Check top-level structure
if not isinstance(event, dict):
    errors.append("Event must be an object")
else:
    # Check required fields
    if "event_type" not in event:
        errors.append("Missing required field: event_type")
    if "payload" not in event:
        errors.append("Missing required field: payload")

    # Check no extra properties at top level
    allowed = {"event_type", "payload"}
    extra = set(event.keys()) - allowed
    if extra:
        errors.append(f"Extra properties at top level: {extra}")

    # Check event_type value
    if "event_type" in event:
        if event["event_type"] not in ["user_signup", "user_deletion"]:
            errors.append(f"Invalid event_type: {event['event_type']}")
        elif event["event_type"] == "user_signup":
            # Validate payload for user_signup
            payload = event.get("payload", {})
            if not isinstance(payload, dict):
                errors.append("Payload must be an object")
            else:
                # Check required fields for user_signup
                if "email" not in payload:
                    errors.append("Missing required field in payload: email")
                if "country" not in payload:
                    errors.append("Missing required field in payload: country")

                # Check no extra properties in payload
                allowed_payload = {"email", "country"}
                extra_payload = set(payload.keys()) - allowed_payload
                if extra_payload:
                    errors.append(f"Extra properties in payload: {extra_payload}")

                # Validate email pattern
                if "email" in payload:
                    email = payload["email"]
                    if not isinstance(email, str):
                        errors.append("Email must be a string")
                    elif not re.match(r"^[^@]+@[^@]+\.[^@]+$", email):
                        errors.append(f"Invalid email format: {email}")

                # Validate country pattern (ISO alpha-2)
                if "country" in payload:
                    country = payload["country"]
                    if not isinstance(country, str):
                        errors.append("Country must be a string")
                    elif not re.match(r"^[A-Z]{2}$", country):
                        errors.append(f"Invalid country code: {country}")

if errors:
    print("VALIDATION FAILED:")
    for error in errors:
        print(f"  - {error}")
else:
    print("✓ event.json validates against schema.json")
    print(f"✓ event_type: {event['event_type']}")
    print(f"✓ payload.email: {event['payload']['email']}")
    print(f"✓ payload.country: {event['payload']['country']}")
    print("✓ No extra properties found")
EOF
